fn is_archive_by_extension(path: &Path) -> bool {
    let name = path
        .file_name()
        .and_then(|n| n.to_str())
        .unwrap_or("");
    let name_lower = name.to_lowercase();

    name_lower.ends_with(".tar.gz")
        || name_lower.ends_with(".tgz")
        || name_lower.ends_with(".tar.bz2")
        || name_lower.ends_with(".tbz2")
        || name_lower.ends_with(".tar.xz")
        || name_lower.ends_with(".txz")
        || name_lower.ends_with(".tar.zst")
        || name_lower.ends_with(".tzst")
        || name_lower.ends_with(".tar")
        || name_lower.ends_with(".zip")
}

fn collect_files(dir: &Path, files: &mut Vec<PathBuf>) -> Result<()> {
    for entry in std::fs::read_dir(dir)? {
        let entry = entry?;
        let path = entry.path();
        if path.is_symlink() {
            continue;
        }
        if path.is_dir() {
            collect_files(&path, files)?;
        } else if path.is_file() {
            files.push(path);
        }
    }
    Ok(())
}

fn extract_tar_to(archive: &Path, dest: &Path) -> Result<()> {
    let file = std::fs::File::open(archive)?;
    let name = archive
        .file_name()
        .and_then(|n| n.to_str())
        .unwrap_or("");
    let name_lower = name.to_lowercase();

    let reader: Box<dyn Read> = if name_lower.ends_with(".tar.gz") || name_lower.ends_with(".tgz") {
        Box::new(flate2::read::GzDecoder::new(file))
    } else if name_lower.ends_with(".tar.bz2") || name_lower.ends_with(".tbz2") {
        Box::new(bzip2::read::BzDecoder::new(file))
    } else if name_lower.ends_with(".tar.xz") || name_lower.ends_with(".txz") {
        Box::new(xz2::read::XzDecoder::new(file))
    } else if name_lower.ends_with(".tar.zst") || name_lower.ends_with(".tzst") {
        Box::new(zstd::stream::read::Decoder::new(file)?)
    } else {
        Box::new(file)
    };

    let mut archive = tar::Archive::new(reader);
    let entries: Vec<_> = archive
        .entries()?
        .filter_map(|e| e.ok())
        .filter(|e| match e.header().entry_type() {
            tar::EntryType::Regular | tar::EntryType::Continuous => true,
            _ => false,
        })
        .collect();

    for mut entry in entries {
        entry.unpack_in(dest)?;
    }

    Ok(())
}

fn extract_zip_to(archive: &Path, dest: &Path) -> Result<()> {
    let file = std::fs::File::open(archive)?;
    let mut zip = zip::ZipArchive::new(file)?;

    for i in 0..zip.len() {
        let mut entry = zip.by_index(i)?;
        if entry.is_dir() || entry.is_symlink() {
            continue;
        }
        let out_path = match entry.enclosed_name() {
            Some(p) => dest.join(p),
            None => continue,
        };
        if let Some(parent) = out_path.parent() {
            std::fs::create_dir_all(parent)?;
        }
        let mut out = std::fs::File::create(&out_path)?;
        std::io::copy(&mut entry, &mut out)?;
    }

    Ok(())
}

fn extract_archive_to_temp(archive: &Path) -> Result<(tempfile::TempDir, Vec<PathBuf>)> {
    let tmp = tempfile::tempdir()?;

    let name = archive
        .file_name()
        .and_then(|n| n.to_str())
        .unwrap_or("");
    let name_lower = name.to_lowercase();

    let is_zip = name_lower.ends_with(".zip");
    if is_zip {
        extract_zip_to(archive, tmp.path())?;
    } else {
        extract_tar_to(archive, tmp.path())?;
    }

    let mut files = Vec::new();
    collect_files(tmp.path(), &mut files);

    const MAX_FILES: usize = 20;
    files.truncate(MAX_FILES);

    Ok((tmp, files))
}

