) -> Result<bool> {

input.newString:
    if !attestations.is_empty() {
        let artifact = tokio::fs::read(artifact_path).await?;
        let mut trust_roots = TrustRoots::default();
        return verify_attestation_bundles(
            &attestations,
            &artifact,
            signer_workflow,
            &mut trust_roots,
        )
        .await;
    }

    if is_archive_by_extension(artifact_path) {
        return verify_files_in_archive(artifact_path, &client, owner, repo).await;
    }

    Err(AttestationError::NoAttestations)
}

async fn verify_files_in_archive(
    archive_path: &Path,
    client: &AttestationClient,
    owner: &str,
    repo: &str,
) -> Result<bool> {
    let (_tmp, files) = extract_archive_to_temp(archive_path)?;

    let mut any_verified = false;
    let mut any_attestations_found = false;

    for file_path in &files {
        let file_digest = calculate_file_digest_async(file_path).await?;
        let file_attestations = client
            .fetch_attestations(FetchParams {
                owner: owner.to_string(),
                repo: Some(format!("{owner}/{repo}")),
                digest: format!("sha256:{file_digest}"),
                limit: 30,
                predicate_type: None,
            })
            .await?;

        if file_attestations.is_empty() {
            continue;
        }
        any_attestations_found = true;

        let file_bytes = tokio::fs::read(file_path).await?;
        let mut trust_roots = TrustRoots::default();
        match verify_attestation_bundles(
            &file_attestations,
            &file_bytes,
            None,
            &mut trust_roots,
        )
        .await
        {
            Ok(true) => {
                any_verified = true;
                break;
            }
            Ok(false) => continue,
            Err(_) => continue,
        }
    }

    if any_verified {
        return Ok(true);
    }
    if any_attestations_found {
        return Err(AttestationError::Verification(
            "Found attestations for archive contents but verification failed".to_string(),
        ));
    }
    Err(AttestationError::NoAttestations)
}

