    mod archive_fallback {
        use super::*;
        use flate2::write::GzEncoder;
        use flate2::Compression;
        use std::io::Write;

        fn create_test_tar_gz(path: &Path, files: &[(&str, &[u8])]) {
            let file = std::fs::File::create(path).unwrap();
            let enc = GzEncoder::new(file, Compression::default());
            let mut tar = tar::Builder::new(enc);
            for (name, content) in files {
                let mut header = tar::Header::new_gnu();
                header.set_path(name).unwrap();
                header.set_size(content.len() as u64);
                header.set_cksum();
                tar.append(&header, &content[..]).unwrap();
            }
            let enc = tar.into_inner().unwrap();
            enc.finish().unwrap();
        }

        fn create_test_zip(path: &Path, files: &[(&str, &[u8])]) {
            let file = std::fs::File::create(path).unwrap();
            let mut zip = zip::ZipWriter::new(file);
            let options = zip::write::FileOptions::<()>::default()
                .compression_method(zip::CompressionMethod::Deflated);
            for (name, content) in files {
                zip.start_file(*name, options).unwrap();
                zip.write_all(content).unwrap();
            }
            zip.finish().unwrap();
        }

        #[test]
        fn is_archive_recognizes_archive_extensions() {
            assert!(is_archive_by_extension(Path::new("tool.tar.gz")));
            assert!(is_archive_by_extension(Path::new("tool.tgz")));
            assert!(is_archive_by_extension(Path::new("tool.tar.bz2")));
            assert!(is_archive_by_extension(Path::new("tool.tbz2")));
            assert!(is_archive_by_extension(Path::new("tool.tar.xz")));
            assert!(is_archive_by_extension(Path::new("tool.txz")));
            assert!(is_archive_by_extension(Path::new("tool.tar.zst")));
            assert!(is_archive_by_extension(Path::new("tool.tzst")));
            assert!(is_archive_by_extension(Path::new("tool.tar")));
            assert!(is_archive_by_extension(Path::new("tool.zip")));
            assert!(is_archive_by_extension(Path::new("TOOL.TAR.GZ")));
        }

        #[test]
        fn is_archive_rejects_non_archive_extensions() {
            assert!(!is_archive_by_extension(Path::new("tool")));
            assert!(!is_archive_by_extension(Path::new("tool.gz")));
            assert!(!is_archive_by_extension(Path::new("tool.bz2")));
            assert!(!is_archive_by_extension(Path::new("tool.xz")));
            assert!(!is_archive_by_extension(Path::new("tool.zst")));
            assert!(!is_archive_by_extension(Path::new("tool.bin")));
            assert!(!is_archive_by_extension(Path::new("tool.exe")));
            assert!(!is_archive_by_extension(Path::new("tool.dmg")));
            assert!(!is_archive_by_extension(Path::new("")));
        }

        #[test]
        fn extract_tar_gz_collects_regular_files() {
            let tmp = tempfile::tempdir().unwrap();
            let archive_path = tmp.path().join("test.tar.gz");
            create_test_tar_gz(
                &archive_path,
                &[("binary", b"#!/bin/sh\necho hello\n"), ("README.md", b"Test\n")],
            );

            let (_extracted_dir, files) = extract_archive_to_temp(&archive_path).unwrap();
            assert_eq!(files.len(), 2);

            let mut names: Vec<String> = files
                .iter()
                .map(|p| p.file_name().unwrap().to_str().unwrap().to_string())
                .collect();
            names.sort();
            assert_eq!(names, vec!["README.md", "binary"]);

            let readme = files.iter().find(|p| p.ends_with("README.md")).unwrap();
            assert_eq!(std::fs::read_to_string(readme).unwrap(), "Test\n");
        }

        #[test]
        fn extract_tar_gz_with_top_level_dir_collects_nested_files() {
            let tmp = tempfile::tempdir().unwrap();
            let archive_path = tmp.path().join("nested.tar.gz");

            let file = std::fs::File::create(&archive_path).unwrap();
            let enc = GzEncoder::new(file, Compression::default());
            let mut tar = tar::Builder::new(enc);
            for (path, content) in &[
                ("tool-1.0.0/binary", b"binary\n" as &[u8]),
                ("tool-1.0.0/sub/deep", b"deep\n"),
            ] {
                let mut header = tar::Header::new_gnu();
                header.set_path(path).unwrap();
                header.set_size(content.len() as u64);
                header.set_cksum();
                tar.append(&header, &content[..]).unwrap();
            }
            let enc = tar.into_inner().unwrap();
            enc.finish().unwrap();

            let (_extracted_dir, files) = extract_archive_to_temp(&archive_path).unwrap();
            assert_eq!(files.len(), 2);

            let mut names: Vec<String> = files
                .iter()
                .map(|p| p.file_name().unwrap().to_str().unwrap().to_string())
                .collect();
            names.sort();
            assert_eq!(names, vec!["binary", "deep"]);
        }

        #[test]
        fn extract_zip_collects_files() {
            let tmp = tempfile::tempdir().unwrap();
            let archive_path = tmp.path().join("test.zip");
            create_test_zip(
                &archive_path,
                &[("tool", b"binary content\n"), ("LICENSE", b"MIT\n")],
            );

            let (_extracted_dir, files) = extract_archive_to_temp(&archive_path).unwrap();
            assert_eq!(files.len(), 2);

            let tool_path = files.iter().find(|p| p.ends_with("tool")).unwrap();
            assert_eq!(
                std::fs::read_to_string(tool_path).unwrap(),
                "binary content\n"
            );
        }

        #[test]
        fn extract_archive_truncates_file_list() {
            let tmp = tempfile::tempdir().unwrap();
            let archive_path = tmp.path().join("many.tar.gz");

            let file = std::fs::File::create(&archive_path).unwrap();
            let enc = GzEncoder::new(file, Compression::default());
            let mut tar = tar::Builder::new(enc);
            for i in 0..25 {
                let name = format!("file_{i}");
                let content = format!("content {i}\n");
                let mut header = tar::Header::new_gnu();
                header.set_path(&name).unwrap();
                header.set_size(content.len() as u64);
                header.set_cksum();
                tar.append(&header, content.as_bytes()).unwrap();
            }
            let enc = tar.into_inner().unwrap();
            enc.finish().unwrap();

            let (_extracted_dir, files) = extract_archive_to_temp(&archive_path).unwrap();
            assert!(
                files.len() <= 20,
                "should truncate at 20, got {}",
                files.len()
            );
        }

        #[test]
        fn extract_tar_gz_skips_symlinks_and_dirs() {
            let tmp = tempfile::tempdir().unwrap();
            let archive_path = tmp.path().join("with_symlink.tar.gz");

            let file = std::fs::File::create(&archive_path).unwrap();
            let enc = GzEncoder::new(file, Compression::default());
            let mut tar = tar::Builder::new(enc);

            let mut dir_header = tar::Header::new_gnu();
            dir_header.set_path("somedir").unwrap();
            dir_header.set_entry_type(tar::EntryType::Directory);
            dir_header.set_size(0);
            dir_header.set_cksum();
            tar.append(&dir_header, &[][..]).unwrap();

            let mut reg_header = tar::Header::new_gnu();
            reg_header.set_path("thebinary").unwrap();
            reg_header.set_entry_type(tar::EntryType::Regular);
            reg_header.set_size(4);
            reg_header.set_cksum();
            tar.append(&reg_header, b"data").unwrap();

            let mut link_header = tar::Header::new_gnu();
            link_header.set_path("link").unwrap();
            link_header.set_entry_type(tar::EntryType::Symlink);
            link_header.set_size(0);
            link_header.set_cksum();
            tar.append(&link_header, &[][..]).unwrap();

            let enc = tar.into_inner().unwrap();
            enc.finish().unwrap();

            let (_extracted_dir, files) = extract_archive_to_temp(&archive_path).unwrap();
            assert_eq!(files.len(), 1);
            assert_eq!(
                files[0].file_name().unwrap().to_str().unwrap(),
                "thebinary"
            );
        }

        #[test]
        fn file_digest_is_stable() {
            let tmp = tempfile::tempdir().unwrap();
            let file_path = tmp.path().join("test.bin");
            std::fs::write(&file_path, b"hello world\n").unwrap();

            let rt = tokio::runtime::Runtime::new().unwrap();
            let digest1 = rt
                .block_on(calculate_file_digest_async(&file_path))
                .unwrap();
            let digest2 = rt
                .block_on(calculate_file_digest_async(&file_path))
                .unwrap();
            assert_eq!(digest1, digest2);
            assert_eq!(digest1.len(), 64);

            std::fs::write(&file_path, b"different\n").unwrap();
            let digest3 = rt
                .block_on(calculate_file_digest_async(&file_path))
                .unwrap();
            assert_ne!(digest1, digest3);
        }

        #[test]
        fn extract_archive_temp_dir_cleaned_up() {
            let tmp = tempfile::tempdir().unwrap();
            let archive_path = tmp.path().join("test.tar.gz");
            create_test_tar_gz(&archive_path, &[("f", b"x")]);

            let dir_path: PathBuf;
            {
                let (extracted_dir, _files) = extract_archive_to_temp(&archive_path).unwrap();
                dir_path = extracted_dir.path().to_path_buf();
                assert!(dir_path.exists());
            }
            assert!(!dir_path.exists());
        }

        #[test]
        fn extract_tar_gz_verify_file_content_integrity() {
            let tmp = tempfile::tempdir().unwrap();
            let archive_path = tmp.path().join("content_test.tar.gz");
            let original_content = b"exact content for integrity check\n";
            create_test_tar_gz(&archive_path, &[("payload", original_content)]);

            let (_extracted_dir, files) = extract_archive_to_temp(&archive_path).unwrap();
            assert_eq!(files.len(), 1);
            let extracted_content = std::fs::read(&files[0]).unwrap();
            assert_eq!(extracted_content, original_content);
        }

        #[tokio::test]
        async fn archive_fallback_fail_closed_when_file_attestations_exist_but_fail() {
            let tmp = tempfile::tempdir().unwrap();
            let archive_path = tmp.path().join("test.tar.gz");
            create_test_tar_gz(&archive_path, &[("binary", b"binary content\n")]);

            let mut server = mockito::Server::new_async().await;

            let archive_digest = calculate_file_digest_async(&archive_path).await.unwrap();
            let archive_path_str = format!(
                "/repos/owner/repo/attestations/sha256:{archive_digest}?per_page=30"
            );
            let archive_mock = server
                .mock("GET", archive_path_str.as_str())
                .with_status(404)
                .with_header("content-type", "application/json")
                .create_async()
                .await;

            let binary_path = tmp.path().join("binary");
            std::fs::write(&binary_path, b"binary content\n").unwrap();
            let binary_digest = calculate_file_digest_async(&binary_path).await.unwrap();

            let fake_bundle = serde_json::json!({
                "mediaType": "application/vnd.dev.sigstore.bundle.v0.3+json",
                "verificationMaterial": {
                    "x509CertificateChain": { "certificates": [] }
                },
                "dsseEnvelope": {}
            });
            let attestation_response = serde_json::json!({
                "attestations": [{
                    "bundle": fake_bundle
                }]
            });

            let file_path_str = format!(
                "/repos/owner/repo/attestations/sha256:{binary_digest}?per_page=30"
            );
            let _file_mock = server
                .mock("GET", file_path_str.as_str())
                .with_status(200)
                .with_header("content-type", "application/json")
                .with_body(serde_json::to_string(&attestation_response).unwrap())
                .create_async()
                .await;

            let result = verify_github_attestation_with_base_url(
                &archive_path,
                "owner",
                "repo",
                None,
                None,
                &server.url(),
            )
            .await;

            archive_mock.assert_async().await;
            match result {
                Err(AttestationError::Verification(msg)) => {
                    assert!(
                        msg.contains("archive contents"),
                        "expected archive-contents verification error, got: {msg}"
                    );
                }
                Ok(_) => panic!("expected verification error for fail-closed, got Ok"),
                Err(other) => {
                    panic!("expected Verification error for fail-closed, got: {other}")
                }
            }
        }

        #[tokio::test]
        async fn archive_fallback_fail_closed_when_no_attestations_at_any_level() {
            let tmp = tempfile::tempdir().unwrap();
            let archive_path = tmp.path().join("test.tar.gz");
            create_test_tar_gz(&archive_path, &[("binary", b"binary\n")]);

            let mut server = mockito::Server::new_async().await;

            let archive_digest = calculate_file_digest_async(&archive_path).await.unwrap();
            let archive_path_str = format!(
                "/repos/owner/repo/attestations/sha256:{archive_digest}?per_page=30"
            );
            let archive_mock = server
                .mock("GET", archive_path_str.as_str())
                .with_status(404)
                .with_header("content-type", "application/json")
                .create_async()
                .await;

            let binary_path = tmp.path().join("binary");
            std::fs::write(&binary_path, b"binary\n").unwrap();
            let binary_digest = calculate_file_digest_async(&binary_path).await.unwrap();

            let file_path_str = format!(
                "/repos/owner/repo/attestations/sha256:{binary_digest}?per_page=30"
            );
            let file_mock = server
                .mock("GET", file_path_str.as_str())
                .with_status(404)
                .with_header("content-type", "application/json")
                .create_async()
                .await;

            let result = verify_github_attestation_with_base_url(
                &archive_path,
                "owner",
                "repo",
                None,
                None,
                &server.url(),
            )
            .await;

            archive_mock.assert_async().await;
            file_mock.assert_async().await;
            match result {
                Err(AttestationError::NoAttestations) => {}
                Ok(_) => panic!("expected NoAttestations, got Ok"),
                Err(other) => panic!("expected NoAttestations, got: {other}"),
            }
        }

        #[tokio::test]
        async fn non_archive_file_no_attestations_returns_no_attestations() {
            let tmp = tempfile::tempdir().unwrap();
            let file_path = tmp.path().join("plain-binary");
            std::fs::write(&file_path, b"plain binary content\n").unwrap();

            let mut server = mockito::Server::new_async().await;

            let digest = calculate_file_digest_async(&file_path).await.unwrap();
            let path_str = format!("/repos/owner/repo/attestations/sha256:{digest}?per_page=30");
            let mock = server
                .mock("GET", path_str.as_str())
                .with_status(404)
                .with_header("content-type", "application/json")
                .create_async()
                .await;

            let result = verify_github_attestation_with_base_url(
                &file_path,
                "owner",
                "repo",
                None,
                None,
                &server.url(),
            )
            .await;

            mock.assert_async().await;
            match result {
                Err(AttestationError::NoAttestations) => {}
                Ok(_) => panic!("expected NoAttestations for plain file, got Ok"),
                Err(other) => {
                    panic!("expected NoAttestations for plain file, got: {other}")
                }
            }
        }
    }
